// HubSpot sends an array of events. Parse and route each one.
const webhookNode = $('HubSpot Events Webhook').first();
const body = webhookNode.json.body ?? webhookNode.json;
const config = $input.first().json;
const n8nBaseUrl = (config.owner && config.owner.n8nBaseUrl) ? config.owner.n8nBaseUrl.replace(/\/$/, '') : 'https://n8n.intrawebtech.com';

const events = Array.isArray(body) ? body : (body && typeof body.objectId !== 'undefined' ? [body] : []);
if (events.length === 0) return [];

const dealProps = 'dealname,dealstage,amount,closedate,tier,contact_email,contact_firstname,contact_lastname,contact_phone,industry,deal_pain_points,client_drive_folder_id,monthly_retainer,client_health_score,company';
const contactProps = 'firstname,lastname,company,industry,lead_source,lead_score,hs_lead_status';

const stageCfg = (config.hubspot && config.hubspot.dealStageIds) || {};
const stageCandidates = (raw, fallback) => {
  const parts = (v) => {
    if (v === undefined || v === null || v === '') return [];
    if (Array.isArray(v)) return v.map((x) => String(x).toLowerCase().trim()).filter(Boolean);
    const s = String(v);
    if (s.includes(',')) return s.split(',').map((x) => x.trim().toLowerCase()).filter(Boolean);
    const one = s.toLowerCase().trim();
    return one ? [one] : [];
  };
  const fromRaw = parts(raw);
  if (fromRaw.length) return fromRaw;
  return parts(fallback);
};
const closedWonStages = stageCandidates(stageCfg.closedWon, 'closedwon');
const proposalStages = stageCandidates(stageCfg.proposal, '3382756085');
const contractSentStages = stageCandidates(stageCfg.contractSent, '');
const invoiceSentStages = stageCandidates(stageCfg.invoiceSent, '3382756086');
const paidStages = stageCandidates(stageCfg.paid, '3382756087');
const projectCompleteStages = stageCandidates(stageCfg.projectComplete, '3382756088');

const out = [];
for (const e of events) {
  const eventType = e.eventType || e.subscriptionType || '';
  const objectId = e.objectId;
  const propertyName = e.propertyName || '';
  const propertyValue = String(e.propertyValue || '').toLowerCase();

  if (!objectId) continue;

  let route = 'skip';
  let objectType = '';
  let webhookPath = '';

  if (eventType === 'deal.propertyChange' && propertyName === 'dealstage') {
    objectType = 'deal';

    if (closedWonStages.includes(propertyValue)) {
      route = 'closed_won';
      webhookPath = 'hubspot-deal-closed-won';

    } else if (proposalStages.includes(propertyValue)) {
      route = 'proposal_stage';
      webhookPath = 'hubspot-deal-proposal-stage';

    } else if (contractSentStages.length && contractSentStages.includes(propertyValue)) {
      route = 'contract_sent';
      webhookPath = 'hubspot-deal-contract-sent';

    } else if (invoiceSentStages.includes(propertyValue)) {
      route = 'invoice_sent';
      webhookPath = 'hubspot-deal-invoice-sent';

    } else if (paidStages.includes(propertyValue)) {
      route = 'paid';
      webhookPath = 'hubspot-deal-stage-change';

    } else if (projectCompleteStages.includes(propertyValue)) {
      route = 'project_complete';
      webhookPath = 'hubspot-deal-project-complete';

    } else {
      route = 'deal_stage_change';
      webhookPath = 'hubspot-deal-stage-change';
    }

  } else if (eventType === 'contact.propertyChange' || eventType === 'contact.creation') {
    objectType = 'contact';
    route = 'contact_change';
    webhookPath = 'hubspot-contact-change';
  }

  if (route !== 'skip' && webhookPath) {
    out.push({
      json: {
        route,
        objectId: String(objectId),
        objectType,
        n8nBaseUrl,
        webhookPath,
        dealProps,
        contactProps
      }
    });
  }
}
return out;

